function detectDirectAIActionFlow(workflow: any): string[] {
  const issues: string[] = [];

  workflow.nodes.forEach((node: any) => {
    if (node.type.includes('ai.') && node.type !== 'n8n-nodes-base.aiAgent') return;

    const connections = workflow.connections[node.id] || {};
    Object.values(connections).forEach((targets: any[]) => {
      targets.forEach((target: any) => {
        const targetNode = workflow.nodes.find((n: any) => n.id === target.node);
        if (targetNode?.type.includes('n8n-nodes-base.httpRequest') || 
            targetNode?.type.includes('n8n-nodes-base.executeWorkflow')) {
          issues.push(`Direct flow: ${node.name} → ${targetNode.name}`);
        }
      });
    });
  });

  return issues;
}

function scanJailbreakPatterns(prompt: string): boolean {
  const jailbreakPatterns = [
    /ignore previous instructions/i,
    /you are now/i,
    /system override/i,
    /forget your rules/i,
    /act as.*hacker/i,
    /bypass safety/i,
    /developer mode/i
  ];

  return jailbreakPatterns.some(pattern => pattern.test(prompt));
}

function detectAgentPrompts(workflow: any): string[] {
  return workflow.nodes
    .filter((node: any) => node.type === 'n8n-nodes-base.aiAgent')
    .filter((node: any) => scanJailbreakPatterns(node.parameters.systemMessage || ''))
    .map((node: any) => `Jailbreak in ${node.name}: ${node.parameters.systemMessage}`);
}

function detectCredentialExposure(workflow: any): string[] {
  const issues: string[] = [];
  const credentialPatterns = [/\{\{\$credentials\./, /\{\{$json\./];

  workflow.nodes.forEach((node: any) => {
    if (node.type !== 'n8n-nodes-base.aiAgent') return;

    const tools = node.parameters.tools || [];
    tools.forEach((tool: any, index: number) => {
      if (typeof tool.parameters === 'string') {
        credentialPatterns.forEach(pattern => {
          if (pattern.test(tool.parameters)) {
            issues.push(`Credential exposure in ${node.name}.tools[${index}].parameters`);
          }
        });
      }
    });
  });

  return issues;
}

