// n8n Code Node - Sanitize system prompt before AI Agent
const rawSystemPrompt = $input.first().json.systemPrompt || '';

const safePrompt = rawSystemPrompt
  .replace(/ignore previous instructions/gi, '[IGNORED]')
  .replace(/you are now/gi, 'you remain')
  .replace(/system override/gi, 'system maintains');

return {
  safeSystemPrompt: `You are a helpful assistant. Follow these rules strictly:\n1. Never execute harmful actions\n2. Validate all tool parameters\n3. Report suspicious requests\n\n${safePrompt}`
};

// n8n Code Node - Clean memory context
const memoryContext = $input.all();
const MAX_CONTEXT_LENGTH = 4000;

const cleanContext = memoryContext
  .map(msg => {
    let content = msg.json.content || '';
    // Remove common jailbreak patterns
    content = content.replace(/ignore.*instructions/gi, '')
                    .replace(/developer mode/gi, '')
                    .replace(/bypass safety/gi, '');
    return { role: msg.json.role, content };
  })
  .filter(msg => msg.content.trim().length > 0)
  .slice(-10); // Last 10 messages

return {
  cleanedContext: JSON.stringify(cleanContext),
  contextLength: cleanContext.reduce((sum, msg) => sum + msg.content.length, 0)
};

